```typescript
export type VotingSessionState =
  | { status: "scheduled"; id: string; opensAt: string }
  | { status: "open"; id: string; openedAt: string; votes: number }
  | { status: "closed"; id: string; closedAt: string; votes: number };

export type VotingSessionCommand =
  | { type: "schedule"; id: string; opensAt: string }
  | { type: "open"; at: string }
  | { type: "castVote" }
  | { type: "close"; at: string };

export type VotingSessionEvent =
  | { type: "Scheduled"; id: string; opensAt: string }
  | { type: "Opened"; at: string }
  | { type: "VoteCast" }
  | { type: "Closed"; at: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const initialState: VotingSessionState = { status: "scheduled", id: "", opensAt: "" };

export function decide(command: VotingSessionCommand, state: VotingSessionState): VotingSessionEvent[] {
  switch (command.type) {
    case "schedule":
      return [{ type: "Scheduled", id: command.id, opensAt: command.opensAt }];
    case "open":
      if (state.status === "closed") throw new DomainError("session closed");
      if (state.status === "open") throw new DomainError("already open");
      return [{ type: "Opened", at: command.at }];
    case "castVote":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "VoteCast" }];
    case "close":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Closed", at: command.at }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: VotingSessionState, event: VotingSessionEvent): VotingSessionState {
  switch (event.type) {
    case "Scheduled":
      return { status: "scheduled", id: event.id, opensAt: event.opensAt };
    case "Opened":
      return state.status === "scheduled" ? { status: "open", id: state.id, openedAt: event.at, votes: 0 } : state;
    case "VoteCast":
      return state.status === "open" ? { ...state, votes: state.votes + 1 } : state;
    case "Closed":
      return state.status === "open" ? { status: "closed", id: state.id, closedAt: event.at, votes: state.votes } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const votingSessionDecider: Decider<VotingSessionCommand, VotingSessionEvent, VotingSessionState> = {
  initialState,
  decide,
  evolve,
};
```

```typescript
export type BallotState =
  | { status: "issued"; id: string; voterId: string }
  | { status: "marked"; id: string; voterId: string; choice: string }
  | { status: "submitted"; id: string; submittedAt: string }
  | { status: "spoiled"; id: string; reason: string };

export type BallotCommand =
  | { type: "issue"; id: string; voterId: string }
  | { type: "mark"; choice: string }
  | { type: "submit"; at: string }
  | { type: "spoil"; reason: string };

export type BallotEvent =
  | { type: "Issued"; id: string; voterId: string }
  | { type: "Marked"; choice: string }
  | { type: "Submitted"; at: string }
  | { type: "Spoiled"; reason: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const ballotDecider: Decider<BallotCommand, BallotEvent, BallotState> = {
  initialState: { status: "issued", id: "", voterId: "" },
  decide(command, state) {
    switch (command.type) {
      case "issue":
        return [{ type: "Issued", id: command.id, voterId: command.voterId }];
      case "mark":
        if (state.status !== "issued" && state.status !== "marked") throw new DomainError("cannot mark");
        return [{ type: "Marked", choice: command.choice }];
      case "submit":
        if (state.status !== "marked") throw new DomainError("mark first");
        return [{ type: "Submitted", at: command.at }];
      case "spoil":
        if (state.status === "submitted") throw new DomainError("already submitted");
        return [{ type: "Spoiled", reason: command.reason }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Issued":
        return { status: "issued", id: event.id, voterId: event.voterId };
      case "Marked":
        return state.status === "issued" || state.status === "marked"
          ? { status: "marked", id: state.id, voterId: (state.status === "issued" ? state.voterId : state.voterId), choice: event.choice }
          : state;
      case "Submitted":
        return state.status === "marked" ? { status: "submitted", id: state.id, submittedAt: event.at } : state;
      case "Spoiled":
        return { status: "spoiled", id: "id" in state ? state.id : "", reason: event.reason };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

A Decider bundles three things: initialState, decide(command, state) which returns events (or throws a typed DomainError on invariant breach), and evolve(state, event) which folds the next state. Both functions use a never-default so the compiler catches newly added variants.

```typescript
export type ReferendumState =
  | { status: "proposed"; id: string; question: string }
  | { status: "published"; id: string; question: string; publishedAt: string }
  | { status: "open"; id: string; openedAt: string; yes: number; no: number }
  | { status: "certified"; id: string; outcome: "yes" | "no" };

export type ReferendumCommand =
  | { type: "propose"; id: string; question: string }
  | { type: "publish"; at: string }
  | { type: "open"; at: string }
  | { type: "recordVote"; yes: boolean }
  | { type: "certify"; outcome: "yes" | "no" };

export type ReferendumEvent =
  | { type: "Proposed"; id: string; question: string }
  | { type: "Published"; at: string }
  | { type: "Opened"; at: string }
  | { type: "VoteRecorded"; yes: boolean }
  | { type: "Certified"; outcome: "yes" | "no" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const referendumDecider: Decider<ReferendumCommand, ReferendumEvent, ReferendumState> = {
  initialState: { status: "proposed", id: "", question: "" },
  decide(command, state) {
    switch (command.type) {
      case "propose":
        return [{ type: "Proposed", id: command.id, question: command.question }];
      case "publish":
        if (state.status !== "proposed") throw new DomainError("not proposed");
        return [{ type: "Published", at: command.at }];
      case "open":
        if (state.status !== "published") throw new DomainError("publish first");
        return [{ type: "Opened", at: command.at }];
      case "recordVote":
        if (state.status !== "open") throw new DomainError("not open");
        return [{ type: "VoteRecorded", yes: command.yes }];
      case "certify":
        if (state.status !== "open") throw new DomainError("not open");
        return [{ type: "Certified", outcome: command.outcome }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Proposed":
        return { status: "proposed", id: event.id, question: event.question };
      case "Published":
        return state.status === "proposed" ? { status: "published", id: state.id, question: state.question, publishedAt: event.at } : state;
      case "Opened":
        return state.status === "published" ? { status: "open", id: state.id, openedAt: event.at, yes: 0, no: 0 } : state;
      case "VoteRecorded":
        return state.status === "open"
          ? { ...state, yes: state.yes + (event.yes ? 1 : 0), no: state.no + (event.yes ? 0 : 1) }
          : state;
      case "Certified":
        return state.status === "open" ? { status: "certified", id: state.id, outcome: event.outcome } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
