```typescript
export type CandidateState =
  | { status: "none" }
  | { status: "nominated"; id: string; name: string; party: string }
  | { status: "verified"; id: string; name: string; party: string; verifiedAt: string }
  | { status: "stepped-down"; id: string; steppedDownAt: string };

export type CandidateCommand =
  | { type: "nominate"; id: string; name: string; party: string }
  | { type: "verify"; at: string }
  | { type: "stepDown"; at: string };

export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string }
  | { type: "Verified"; at: string }
  | { type: "SteppedDown"; at: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const candidateDecider: Decider<CandidateCommand, CandidateEvent, CandidateState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "nominate":
        if (state.status !== "none") throw new DomainError("already nominated");
        return [{ type: "Nominated", id: command.id, name: command.name, party: command.party }];
      case "verify":
        if (state.status !== "nominated") throw new DomainError("not nominated");
        return [{ type: "Verified", at: command.at }];
      case "stepDown":
        if (state.status === "stepped-down") throw new DomainError("already stepped down");
        if (state.status === "none") throw new DomainError("not registered");
        return [{ type: "SteppedDown", at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Nominated":
        return { status: "nominated", id: event.id, name: event.name, party: event.party };
      case "Verified":
        return state.status === "nominated"
          ? { status: "verified", id: state.id, name: state.name, party: state.party, verifiedAt: event.at }
          : state;
      case "SteppedDown":
        return state.status === "nominated" || state.status === "verified"
          ? { status: "stepped-down", id: state.id, steppedDownAt: event.at }
          : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
