```typescript
export type VotingSessionEvent =
  | { type: "Scheduled"; id: string; opensAt: string }
  | { type: "Opened"; at: string }
  | { type: "VoteCast" }
  | { type: "Closed"; at: string };

export type SessionView = {
  id: string | null;
  status: "scheduled" | "open" | "closed" | null;
  opensAt: string | null;
  totalVotes: number;
};

export const emptyView: SessionView = {
  id: null,
  status: null,
  opensAt: null,
  totalVotes: 0,
};

export function project(view: SessionView, event: VotingSessionEvent): SessionView {
  switch (event.type) {
    case "Scheduled":
      return { ...view, id: event.id, opensAt: event.opensAt, status: "scheduled" };
    case "Opened":
      return { ...view, status: "open" };
    case "VoteCast":
      return { ...view, totalVotes: view.totalVotes + 1 };
    case "Closed":
      return { ...view, status: "closed" };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function projectAll(events: VotingSessionEvent[]): SessionView {
  return events.reduce(project, emptyView);
}
```

A projection is a pure function project(view, event) that folds only the events it cares about and leaves the view unchanged for events outside its interest.

```typescript
export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string }
  | { type: "Verified"; at: string }
  | { type: "SteppedDown"; at: string }
  | { type: "VotesTallied"; id: string; delta: number };

export type Standings = {
  entries: Record<string, { name: string; party: string; status: "nominated" | "verified" | "stepped-down"; votes: number }>;
};

export const emptyStandings: Standings = { entries: {} };

export function project(view: Standings, event: CandidateEvent): Standings {
  switch (event.type) {
    case "Nominated":
      return { entries: { ...view.entries, [event.id]: { name: event.name, party: event.party, status: "nominated", votes: 0 } } };
    case "Verified": {
      const ids = Object.keys(view.entries);
      if (ids.length === 0) return view;
      const last = ids[ids.length - 1]!;
      const entry = view.entries[last]!;
      return { entries: { ...view.entries, [last]: { ...entry, status: "verified" } } };
    }
    case "SteppedDown": {
      const ids = Object.keys(view.entries);
      if (ids.length === 0) return view;
      const last = ids[ids.length - 1]!;
      const entry = view.entries[last]!;
      return { entries: { ...view.entries, [last]: { ...entry, status: "stepped-down" } } };
    }
    case "VotesTallied": {
      const entry = view.entries[event.id];
      if (!entry) return view;
      return { entries: { ...view.entries, [event.id]: { ...entry, votes: entry.votes + event.delta } } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}
