export type RollEvent =
  | { type: "VoterRegistered"; voterId: string; party: string }
  | { type: "VoterRemoved"; voterId: string };

export type RollView = { voters: number };
export const emptyView: RollView = { voters: 0 };
export function project(view: RollView, event: RollEvent): RollView {
  switch (event.type) {
    case "VoterRegistered": return { voters: view.voters + 1 };
    case "VoterRemoved": return { voters: Math.max(0, view.voters - 1) };
    default: { const _: never = event; return _; }
  }
}
