export function decide(cmd: VotingSessionCommand, s: VotingSessionState): VotingSessionEvent[] {
  switch (cmd.type) {
    case "open":
      if (s.status !== "scheduled") throw new DomainError("not scheduled");
      return [{ type: "Opened", at: cmd.at }];
    case "castVote":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "VoteCast" }];
    case "close":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "Closed", at: cmd.at }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export function evolve(s: VotingSessionState, e: VotingSessionEvent): VotingSessionState {
  switch (e.type) {
    case "Opened":
      return s.status === "scheduled" ? { status: "open", id: s.id, votes: 0 } : s;
    case "VoteCast":
      return s.status === "open" ? { ...s, votes: s.votes + 1 } : s;
    case "Closed":
      return s.status === "open" ? { status: "closed", id: s.id, votes: s.votes } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): AsyncIterable<VotingSessionEvent>;
  appendToStream(stream: string, events: VotingSessionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ revision: bigint }>;
  currentRevision(stream: string): Promise<bigint | null>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const handler: CommandHandler<VotingSessionCommand> = {
  async handle(command, { streamName, eventStore }) {
    let state = initialState;
    for await (const e of eventStore.readStream(streamName)) {
      state = evolve(state, e);
    }
    const events = decide(command, state);
    const rev = await eventStore.currentRevision(streamName);
    await eventStore.appendToStream(streamName, events, { expectedRevision: rev ?? "no_stream" });
  },
};
```

A CommandHandler orchestrates: load current state via readStream+reduce(evolve, initial), run pure decide(command, state), and appendToStream the resulting events with expectedRevision. No business logic lives in the handler.

