import { Effect } from "effect";

export type ReferendumState =
  | { status: "proposed"; id: string }
  | { status: "open"; id: string; yes: number; no: number };

export type ReferendumCommand =
  | { type: "open"; at: string }
  | { type: "vote"; yes: boolean };

export type ReferendumEvent =
  | { type: "Opened"; at: string }
  | { type: "Voted"; yes: boolean };

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export const initialState: ReferendumState = { status: "proposed", id: "" };

export function decide(cmd: ReferendumCommand, s: ReferendumState): ReferendumEvent[] {
  switch (cmd.type) {
    case "open":
      if (s.status !== "proposed") throw new DomainError("not proposed");
      return [{ type: "Opened", at: cmd.at }];
    case "vote":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "Voted", yes: cmd.yes }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export function evolve(s: ReferendumState, e: ReferendumEvent): ReferendumState {
  switch (e.type) {
    case "Opened":
      return s.status === "proposed" ? { status: "open", id: s.id, yes: 0, no: 0 } : s;
    case "Voted":
      return s.status === "open"
        ? { ...s, yes: s.yes + (e.yes ? 1 : 0), no: s.no + (e.yes ? 0 : 1) }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReferendumEvent[]>;
  appendToStream(stream: string, events: ReferendumEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
  currentRevision(stream: string): Promise<bigint | null>;
}

export function handle(
  store: EventStore,
  streamName: string,
  command: ReferendumCommand,
): Effect.Effect<void, DomainError | ConcurrencyConflict> {
  return Effect.gen(function* () {
    const events = yield* Effect.promise(() => store.readStream(streamName));
    const state = events.reduce(evolve, initialState);
    const next = decide(command, state);
    const rev = yield* Effect.promise(() => store.currentRevision(streamName));
    yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, next, { expectedRevision: rev ?? "no_stream" }),
      catch: () => new ConcurrencyConflict(),
    });
  });
}
