      return s.status === "nominated" ? { status: "verified", id: s.id, name: s.name, party: s.party } : s;
    case "Withdrawn":
      return s.status === "nominated" || s.status === "verified" ? { status: "withdrawn", id: s.id } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolveFn: (s: S, e: E) => S,
  initialState: S,
): Promise<S> {
  let state: S = initialState;
  for await (const event of stream) {
    state = evolveFn(state, event);
  }
  return state;
}

export function isRegistered(s: CandidateState): s is Exclude<CandidateState, { status: "none" }> {
  return s.status !== "none";
}

export async function loadCandidate(stream: AsyncIterable<CandidateEvent>): Promise<CandidateState> {
  const state = await aggregateStream(stream, evolve, initial);
  if (!isRegistered(state)) throw new Error("candidate stream empty");
  return state;
}
