type RawV2Proposed = { type: "Proposed"; version: 2; id: string; question: string; region: string };
type RawOpened = { type: "Opened"; version: 2; at: string };
type Raw = RawV1Proposed | RawV2Proposed | RawOpened;

function isRaw(raw: unknown): raw is Raw {
  return typeof raw === "object" && raw !== null && "type" in raw && "version" in raw;
}

export function upcast(raw: unknown): ReferendumEvent {
  if (!isRaw(raw)) throw new UnknownEventError(raw);
  switch (raw.type) {
    case "referendum-proposed":
      return { type: "Proposed", id: raw.id, question: raw.question, region: "unknown", version: 2 };
    case "Proposed":
      return { type: "Proposed", id: raw.id, question: raw.question, region: raw.region, version: 2 };
    case "Opened":
      return { type: "Opened", at: raw.at, version: 2 };
    default: {
      const _: never = raw;
      throw new UnknownEventError(_);
