Use a small discriminated union of error classes. decide() throws typed instances; the caller switches on `instanceof` or on a `kind` tag.

```typescript
export class DomainError extends Error {
  readonly kind: string = "DomainError";
}
export class InvalidTransition extends DomainError {
  override readonly kind = "InvalidTransition" as const;
  constructor(public from: string, public command: string) {
    super(`cannot ${command} from ${from}`);
  }
}
export class AlreadyFinalized extends DomainError {
  override readonly kind = "AlreadyFinalized" as const;
  constructor() { super("ballot already finalized"); }
}

export type BallotState =
  | { status: "issued" }
  | { status: "submitted" };

export type BallotCommand =
  | { type: "submit"; at: string }
  | { type: "retract" };

export type BallotEvent =
  | { type: "Submitted"; at: string }
  | { type: "Retracted" };

export function decide(c: BallotCommand, s: BallotState): BallotEvent[] {
  switch (c.type) {
    case "submit":
      if (s.status !== "issued") throw new InvalidTransition(s.status, c.type);
      return [{ type: "Submitted", at: c.at }];
    case "retract":
      if (s.status === "submitted") throw new AlreadyFinalized();
      return [{ type: "Retracted" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}
