  | { type: "Opened"; at: string; position: bigint }
  | { type: "VoteCast"; position: bigint }
  | { type: "Closed"; at: string; position: bigint };

export interface EventStore {
  readPage(stream: string, from: bigint, size: number): Promise<VotingSessionEvent[]>;
}

export async function* readStream(
  store: EventStore,
  stream: string,
  pageSize: number,
): AsyncGenerator<VotingSessionEvent, void, undefined> {
  let cursor: bigint = 0n;
  for (;;) {
    const page = await store.readPage(stream, cursor, pageSize);
    if (page.length === 0) return;
    for (const event of page) {
      yield event;
      cursor = event.position + 1n;
    }
  }
}

export async function toArray(stream: AsyncIterable<VotingSessionEvent>): Promise<VotingSessionEvent[]> {
  const out: VotingSessionEvent[] = [];
  for await (const event of stream) out.push(event);
  return out;
