export type BallotBoxState =
  | { status: "closed" }
  | { status: "open"; count: number };

export type BallotBoxCommand =
  | { type: "open"; at: string }
  | { type: "record" }
  | { type: "seal" };

export type BallotBoxEvent =
  | { type: "Opened"; at: string }
  | { type: "Vote" }
  | { type: "Sealed" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const initialState: BallotBoxState = { status: "closed" };

export function decide(command: BallotBoxCommand, state: BallotBoxState): BallotBoxEvent[] {
  switch (command.type) {
    case "open":
      if (state.status === "open") throw new DomainError("already open");
      return [{ type: "Opened", at: command.at }];
    case "record":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Vote" }];
    case "seal":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Sealed" }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: BallotBoxState, event: BallotBoxEvent): BallotBoxState {
  switch (event.type) {
    case "Opened":
      return { status: "open", count: 0 };
    case "Vote":
      return state.status === "open" ? { ...state, count: state.count + 1 } : state;
    case "Sealed":
      return { status: "closed" };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const ballotBoxDecider: Decider<BallotBoxCommand, BallotBoxEvent, BallotBoxState> = {
  initialState,
  decide,
  evolve,
};
